items.prompt:
Write TypeScript. Implement and `export` a TYPE (not a function) `ParseQuery<S extends string>`
that parses a URL query string literal into an object type at COMPILE TIME:
  ParseQuery<"a=1">          => { a: "1" }
  ParseQuery<"a=1&b=2">      => { a: "1"; b: "2" }
  ParseQuery<"x=hi&y=lo&z=1"> => { x: "hi"; y: "lo"; z: "1" }
  ParseQuery<"">             => {}
Use template-literal types + recursion. This is type-level only — no runtime code, no `any`.
Return ONLY a single ```ts code block.

items.output:
export type ParseQuery<S extends string> = S extends ""
  ? {}
  : S extends `${infer K}=${infer V}&${infer Rest}`
    ? { [key in K]: V } & ParseQuery<Rest>
    : S extends `${infer K}=${infer V}`
      ? { [key in K]: V }
      : {};

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private handlers = new Map<string, Array<(...args: unknown[]) => void>>();

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const existing = this.handlers.get(name) || [];
    existing.push(handler as (...args: unknown[]) => void);
    this.handlers.set(name, existing);
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this.handlers.get(name);
    if (handlers) {
      for (const handler of handlers) {
        handler(...args);
      }
    }
  }
}
